#!/usr/bin/env bash
# UDR Skills installer (POSIX / WSL / Git Bash)
#
# Usage:
#   bash dist/scripts/install.sh <target-project-root> [--gemini] [--codex]
#   bash dist/scripts/install.sh --global [--gemini] [--codex]
#
# Options:
#   --gemini    Gemini CLI 向けセットアップ: GEMINI.md と .gemini/extensions/udr/ を target に生成
#   --codex     Codex CLI 向けセットアップ: AGENTS.md の UDR ポリシーセクションを案内
#
# Behavior:
#   - 既存 udr-* / _udr-shared があれば .bak-<timestamp> に退避
#   - skills を上書きコピー
#   - target に .gitignore がなければ最小ファイルを生成
#   - 最後に /udr-init の実行を案内

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DIST_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
REPO_ROOT="$(cd "$DIST_ROOT/.." && pwd)"
SRC="$REPO_ROOT/.claude/skills"

if [ ! -d "$SRC" ]; then
  echo "ERROR: 展開元 skills ディレクトリが見つかりません: $SRC" >&2
  echo "       (UDR リポジトリの clone から実行していますか？ .claude/skills が source of truth です)" >&2
  exit 1
fi

# 引数パース
TARGET_ARG=""
SETUP_GEMINI=false
SETUP_CODEX=false

for arg in "$@"; do
  case "$arg" in
    --gemini) SETUP_GEMINI=true ;;
    --codex)  SETUP_CODEX=true ;;
    --global) TARGET_ARG="--global" ;;
    -*)
      echo "ERROR: 不明なオプション: $arg" >&2
      echo "Usage: $0 <target-project-root> | --global [--gemini] [--codex]" >&2
      exit 2
      ;;
    *)
      if [ -z "$TARGET_ARG" ]; then
        TARGET_ARG="$arg"
      fi
      ;;
  esac
done

if [ -z "$TARGET_ARG" ]; then
  echo "Usage: $0 <target-project-root> | --global [--gemini] [--codex]" >&2
  exit 2
fi

TS="$(date -u +%Y%m%dT%H%M%S)"

if [ "$TARGET_ARG" = "--global" ]; then
  TARGET_DIR="${HOME}/.claude/skills"
  TARGET_ROOT="${HOME}"
  SCOPE="global (~/.claude/skills)"
else
  if [ ! -d "$TARGET_ARG" ]; then
    echo "ERROR: 対象ディレクトリが存在しません: $TARGET_ARG" >&2
    exit 3
  fi
  TARGET_DIR="$TARGET_ARG/.claude/skills"
  TARGET_ROOT="$TARGET_ARG"
  SCOPE="project ($TARGET_ARG)"
fi

echo ">> Installing UDR Skills"
echo "   scope:  $SCOPE"
echo "   target: $TARGET_DIR"
if $SETUP_GEMINI; then echo "   + Gemini CLI セットアップ"; fi
if $SETUP_CODEX;  then echo "   + Codex CLI セットアップ案内"; fi
echo

mkdir -p "$TARGET_DIR"

# 既存 UDR 関連を退避
backup_if_exists() {
  local name="$1"
  local path="$TARGET_DIR/$name"
  if [ -e "$path" ]; then
    local bak="${path}.bak-${TS}"
    echo "   backup: $name -> $(basename "$bak")"
    mv "$path" "$bak"
  fi
}

for name in _udr-shared udr-init udr-record udr-search udr-sync udr-trace udr-review udr-dashboard README.md; do
  backup_if_exists "$name"
done

# skills コピー
echo ">> Copying skills..."
cp -r "$SRC/"* "$TARGET_DIR/"
echo "   done."
echo

# .gitignore 更新 (プロジェクトローカル展開時のみ)
if [ "$TARGET_ARG" != "--global" ]; then
  GI="$TARGET_ROOT/.gitignore"
  if [ ! -f "$GI" ]; then
    cat > "$GI" <<'GITIGNORE'
# Auto-generated by UDR install.sh
.claude/skills/**/*.bak-*
.udr/index.json
.udr/audit.log*
udr_dashboard.html
GITIGNORE
    echo ">> .gitignore を生成しました: $GI"
  else
    if ! grep -qE '^\.claude/skills/\*\*/\*\.bak-\*' "$GI"; then
      printf '\n# UDR installer backup artifacts\n.claude/skills/**/*.bak-*\n' >> "$GI"
      echo ">> .gitignore にバックアップ除外ルールを追記しました"
    fi
    if ! grep -qE '^\.udr/index\.json' "$GI"; then
      printf '.udr/index.json\n.udr/audit.log*\nudr_dashboard.html\n' >> "$GI"
      echo ">> .gitignore に UDR 除外ルールを追記しました"
    fi
  fi
fi

# VERSION 記録
if [ -f "$DIST_ROOT/VERSION" ]; then
  cp "$DIST_ROOT/VERSION" "$TARGET_DIR/.udr-skills-version"
fi

# ── Gemini CLI セットアップ ──────────────────────────────────
if $SETUP_GEMINI && [ "$TARGET_ARG" != "--global" ]; then
  echo ">> Gemini CLI セットアップ..."

  # GEMINI.md を生成（存在しない場合のみ）
  # テンプレートは .claude/deploy/GEMINI.md（source of truth を直接参照）
  GEMINI_MD="$TARGET_ROOT/GEMINI.md"
  GEMINI_TMPL="$REPO_ROOT/.claude/deploy/GEMINI.md"
  if [ -f "$GEMINI_MD" ]; then
    echo "   GEMINI.md は既に存在します（スキップ）: $GEMINI_MD"
  elif [ -f "$GEMINI_TMPL" ]; then
    cp "$GEMINI_TMPL" "$GEMINI_MD"
    echo "   GEMINI.md を生成しました: $GEMINI_MD"
  else
    echo "   WARN: テンプレートが見つかりません: $GEMINI_TMPL"
  fi

  # .gemini/extensions/udr/ を生成
  # テンプレートは .claude/deploy/.gemini/（source of truth を直接参照）
  GEMINI_EXT="$TARGET_ROOT/.gemini/extensions/udr"
  EXT_TMPL="$REPO_ROOT/.claude/deploy/.gemini/extensions/udr/gemini-extension.json"
  mkdir -p "$GEMINI_EXT"
  if [ -f "$GEMINI_EXT/gemini-extension.json" ]; then
    echo "   .gemini/extensions/udr/gemini-extension.json は既に存在します（スキップ）"
  elif [ -f "$EXT_TMPL" ]; then
    cp "$EXT_TMPL" "$GEMINI_EXT/gemini-extension.json"
    echo "   .gemini/extensions/udr/gemini-extension.json を生成しました"
  else
    echo "   WARN: テンプレートが見つかりません: $EXT_TMPL"
  fi
  echo
fi

# ── Codex CLI セットアップ案内 ────────────────────────────────
if $SETUP_CODEX && [ "$TARGET_ARG" != "--global" ]; then
  echo ">> Codex CLI セットアップ案内"
  echo "   Codex CLI は AGENTS.md を会話開始時に自動で読みます。"
  echo "   UDR ポリシーを AGENTS.md に追加するには:"
  echo "     1. AGENTS.md が存在しない場合は作成します"
  echo "     2. プロジェクト説明と UDR 自動検知ポリシーを記載します"
  echo "   テンプレートは .claude/skills/_udr-shared/templates/codex-prompts/ を参照してください"
  echo "   操作時は codex-prompts/udr-record.md 等を @ファイル参照して実行します"
  echo
fi

echo "=============================================="
echo " UDR Skills 展開完了"
echo "=============================================="
echo
echo " 次のステップ:"
echo "   1. Claude Code で対象プロジェクトを開く"
echo "   2. /udr-init を実行して .udr/ を初期化"
echo "      ※ 使う AI ツール (claude / gemini / codex 等) を選択すること"
echo "   3. /udr-record で最初の判断を記録"
echo "   4. /udr-sync で CLAUDE.md / GEMINI.md / AGENTS.md 等に同期"
echo
if $SETUP_GEMINI && [ "$TARGET_ARG" != "--global" ]; then
  echo " Gemini CLI でも使うには:"
  echo "   - GEMINI.md が生成済み"
  echo "   - .gemini/extensions/udr/ が生成済み"
  echo "   - .udr/config.yaml の tools に gemini を追加"
  echo
fi
echo " バックアップ (もしあれば): *.bak-${TS}"
echo " バージョン: $(cat "$TARGET_DIR/.udr-skills-version" 2>/dev/null | head -1)"
echo
